import Sidebar from "./Sidebar";

function Dashboard() {
  return (
    <div className="flex">
      <Sidebar />

      <div className="flex-1 p-6">
        <h1 className="text-3xl font-bold">
          Dashboard
        </h1>
      </div>
    </div>
  );
}

export default Dashboard;
